impl Solution { pub fn min_deletion_size(strs: Vec<String>) -> i32 { let (n, m) = (strs.len(), strs[0].len()); let mut black_res = 0; let mut black_sorted = vec![false; n - 1]; let black_bytes: Vec<&[u8]> = strs.iter().map(|s| s.as_bytes()).collect(); for j in 0..m { let mut i = 0; while i < n - 1 { if !black_sorted[i] && black_bytes[i][j] > black_bytes[i+1][j] { black_res += 1; break; } i += 1; } if i == n - 1 { for k in 0..n - 1 { if black_bytes[k][j] < black_bytes[k+1][j] { black_sorted[k] = true; } } } } black_res } }